const parseJsonString = (value) => {
  const cleaned = value
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  return JSON.parse(cleaned);
};

let raw = $json.output ?? $json.text ?? $json.response ?? $json;

if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}

if (raw && typeof raw === 'object' && raw.output && typeof raw.output === 'object') {
  raw = raw.output;
}

if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}

if (raw && typeof raw === 'object') {
  return [{ json: raw }];
}

throw new Error('Workflow tidak menghasilkan object JSON yang valid.');

const source = $node["Scoring Docs Evidence"].json ?? {};
const item = $input.first();

const parseJsonString = (value) => {
  const cleaned = String(value)
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  return JSON.parse(cleaned);
};

let raw = item.json?.text ?? item.json?.response ?? item.json?.output ?? item.json;
if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}
if (!raw || typeof raw !== 'object') {
  throw new Error('Basic LLM Chain1 tidak menghasilkan JSON scoring yang valid.');
}

const aiConfidence = Number(Math.max(0, Math.min(1, Number.parseFloat(String(raw.ai_confidence ?? source.ai_confidence ?? 0))))).toFixed(3);
const requirementId = source.requirement_id;
const categoryId = source.category_id;
const fileName = source.file_name || 'document-uploaded-file';

return [{
  json: {
    ...source,
    ai_confidence: Number(aiConfidence),
    ai_scoring_reason: String(raw.reason ?? '').trim(),
    upload_request: {
      method: 'POST',
      path: `/evidence/categories/${categoryId}/documents`,
      formData: {
        requirement_id: requirementId,
        ai_confidence: aiConfidence
      },
      binary_field: 'document'
    },
    curl_preview: `curl --location -g 'https://experientially-unchallenging-amelie.ngrok-free.dev/api/v1/evidence/categories/${categoryId}/documents' \\\n--header 'Authorization: Bearer REPLACE_WITH_USER_TOKEN' \\\n--form 'requirement_id="${requirementId}"' \\\n--form 'document=@"/${fileName}"' \\\n--form 'ai_confidence="${aiConfidence}"'`
  },
  binary: $node["Scoring Docs Evidence"].binary
}];

const webhook = $node["Evidence Vault"];
const source = webhook.json ?? {};
const body = source.body ?? {};
const inputItem = $input.first();
const binarySource = inputItem.binary ?? webhook.binary ?? {};
const binaryPropertyName = binarySource.document ? 'document' : Object.keys(binarySource)[0];
const document = binaryPropertyName ? binarySource[binaryPropertyName] : null;
if (!document || !binaryPropertyName) {
  throw new Error('Form-data `document` wajib dikirim pada webhook Evidence Vault.');
}

const mimeType = String(document.mimeType ?? '').trim();
if (!mimeType.toLowerCase().startsWith('image/')) {
  throw new Error(`Jalur image vision hanya menerima file image/*, tetapi menerima ${mimeType || 'mimeType kosong'}.`);
}

const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
if (!binaryBuffer?.length) {
  throw new Error('Binary image tidak berhasil dibaca dari input item untuk dikirim ke Alibaba Vision.');
}

const requirementId = String(body.requirement_id ?? '').trim().toUpperCase();
const prompt = [
  'Anda menilai bukti kategori Bahan Baku & Sourcing untuk GreenTrust Passport.',
  requirementId ? `Requirement target: ${requirementId}.` : 'Requirement target belum dikirim.',
  'Analisis gambar yang diunggah dan nilai seberapa kuat gambar ini mendukung requirement target.',
  'Kembalikan JSON valid saja dengan schema berikut:',
  '{"image_summary":"","visible_text":[],"visible_objects":[],"document_type_guess":"","evidence_relevance":"","ai_confidence":0}',
  'Aturan:',
  '- image_summary: 1-3 kalimat ringkas terkait isi gambar.',
  '- visible_text: array string teks yang benar-benar terlihat jika ada.',
  '- visible_objects: array string objek utama yang relevan.',
  '- document_type_guess: tebakan jenis dokumen/foto.',
  '- evidence_relevance: alasan singkat keterkaitan gambar terhadap requirement.',
  '- ai_confidence: angka 0 sampai 1, wajib 3 digit desimal. Contoh 0.873.',
  '- Skor tinggi jika bukti visual sangat jelas dan relevan; skor rendah jika ambigu, blur, atau tidak mendukung requirement.',
  '- Jangan kembalikan markdown atau teks di luar JSON.'
].join('\n');

return [{
  json: {
    file_name: document.fileName ?? '',
    mime_type: mimeType,
    provided_requirement_id: requirementId,
    provided_ai_confidence: String(body.ai_confidence ?? '').trim(),
    alibaba_request: {
      model: 'qwen-vl-plus',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You are a precise evidence analyst. Return valid JSON only.'
        },
        {
          role: 'user',
          content: [
            {
              type: 'text',
              text: prompt
            },
            {
              type: 'image_url',
              image_url: {
                url: `data:${mimeType};base64,${binaryBuffer.toString('base64')}`
              }
            }
          ]
        }
      ]
    }
  },
  binary: {
    document
  }
}];

const source = $node["Prepare Image Vision Request"].json ?? {};
const document = $node["Prepare Image Vision Request"].binary?.document;

if (!document) {
  throw new Error("Binary document hilang sebelum proses scoring image evidence.");
}

const normalizeContent = (value) => {
  if (value == null) {
    return "";
  }

  if (typeof value === "string") {
    return value.trim();
  }

  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === "string") return item;
        if (item && typeof item === "object") {
          if (typeof item.text === "string") return item.text;
          if (typeof item.content === "string") return item.content;
          if (typeof item.output_text === "string") return item.output_text;
        }
        return "";
      })
      .join("\n")
      .trim();
  }

  if (typeof value === "object") {
    if (typeof value.text === "string") return value.text.trim();
    if (typeof value.content === "string") return value.content.trim();
    if (typeof value.output_text === "string") return value.output_text.trim();

    if (
      "image_summary" in value ||
      "visible_text" in value ||
      "visible_objects" in value ||
      "document_type_guess" in value ||
      "evidence_relevance" in value ||
      "ai_confidence" in value
    ) {
      return value;
    }
  }

  return String(value).trim();
};

const extractJsonObject = (text) => {
  const cleaned = String(text)
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch {}

  const firstBrace = cleaned.indexOf("{");
  if (firstBrace === -1) {
    throw new Error("Alibaba vision tidak mengandung object JSON.");
  }

  let depth = 0;
  let inString = false;
  let escaped = false;
  let start = -1;

  for (let i = firstBrace; i < cleaned.length; i++) {
    const ch = cleaned[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === "\\") {
      escaped = true;
      continue;
    }

    if (ch === "\"") {
      inString = !inString;
      continue;
    }

    if (inString) {
      continue;
    }

    if (ch === "{") {
      if (depth === 0) start = i;
      depth++;
      continue;
    }

    if (ch === "}") {
      depth--;

      if (depth === 0 && start !== -1) {
        const candidate = cleaned.slice(start, i + 1);
        try {
          return JSON.parse(candidate);
        } catch (error) {
          throw new Error("Alibaba vision mengembalikan JSON tidak valid: " + error.message);
        }
      }
    }
  }

  throw new Error("Alibaba vision tidak mengembalikan object JSON lengkap.");
};

const rawContent =
  $json?.choices?.[0]?.message?.content ??
  $json?.output_text ??
  $json?.content ??
  $json;

const normalizedContent = normalizeContent(rawContent);
const vision =
  normalizedContent && typeof normalizedContent === "object"
    ? normalizedContent
    : extractJsonObject(normalizedContent);

if (!vision || typeof vision !== "object" || Array.isArray(vision)) {
  throw new Error("Alibaba vision tidak mengembalikan object JSON yang valid.");
}

const visibleText = Array.isArray(vision.visible_text)
  ? vision.visible_text.map((item) => String(item).trim()).filter(Boolean)
  : [];

const visibleObjects = Array.isArray(vision.visible_objects)
  ? vision.visible_objects.map((item) => String(item).trim()).filter(Boolean)
  : [];

const aiSummary = String(vision.image_summary ?? "").trim();
const evidenceRelevance = String(vision.evidence_relevance ?? "").trim();
const documentTypeGuess = String(vision.document_type_guess ?? "").trim();

const providedRequirementId = String(source.provided_requirement_id ?? "")
  .trim()
  .toUpperCase();

const categoryId = providedRequirementId.split("-")[0] || "BB";

let aiConfidence = Number.parseFloat(String(vision.ai_confidence ?? ""));

if (!Number.isFinite(aiConfidence)) {
  aiConfidence = 0;
}

aiConfidence = Math.max(0, Math.min(1, aiConfidence));
aiConfidence = Number(aiConfidence.toFixed(3));

const confidenceBand =
  aiConfidence >= 0.8 ? "high" : aiConfidence >= 0.6 ? "medium" : "low";

return [
  {
