        documentTypeGuess ||
        "Analisis gambar berhasil dibuat.",
      ocr_excerpt: visibleText.slice(0, 8).join(" | ").slice(0, 500),
      file_name: source.file_name ?? "",
      mime_type: source.mime_type ?? "",
      vision_analysis: {
        image_summary: aiSummary,
        visible_text: visibleText,
        visible_objects: visibleObjects,
        document_type_guess: documentTypeGuess,
        evidence_relevance: evidenceRelevance,
        ai_confidence: aiConfidence
      }
    },
