const pages = Array.isArray($json.pages) ? $json.pages : [];
const ocrText = pages.map((page) => page.markdown ?? page.text ?? '').join('\n\n').trim();
const normalizedText = `${String(document.fileName ?? '')}\n${ocrText}`.toLowerCase();
const mimeType = String(document.mimeType ?? '').toLowerCase();
const providedRequirementId = String(body.requirement_id ?? '').trim().toUpperCase();
const providedConfidence = Number.parseFloat(String(body.ai_confidence ?? '').trim());
const categoryId = providedRequirementId.split('-')[0] || 'BB';
const categoryMeta = categoryCatalog[categoryId];

if (!categoryMeta) {
  throw new Error(`category_id ${categoryId} belum didukung pada Scoring Docs Evidence.`);
}

const requirements = categoryMeta.requirements;

const evaluate = (requirement) => {
  const matches = requirement.keywords.filter((keyword) => normalizedText.includes(keyword));
  let score = 0.2 + matches.length * 0.1;

  if (requirement.preferImage && mimeType.startsWith('image/')) score += 0.08;
  if (requirement.preferText && ocrText.length >= 40) score += 0.08;
  if (ocrText.length >= 120) score += 0.04;
  if (!ocrText && requirement.preferImage && mimeType.startsWith('image/')) score += 0.06;

  return {
    ...requirement,
    matches,
    score: Math.max(0.05, Math.min(0.98, Number(score.toFixed(2))))
  };
};

const ranked = requirements.map(evaluate).sort((left, right) => right.score - left.score);
const bestMatch = ranked[0];
const selectedMatch = providedRequirementId
  ? ranked.find((item) => item.id === providedRequirementId) ?? bestMatch
  : bestMatch;

let aiConfidence = selectedMatch.score;
if (Number.isFinite(providedConfidence) && providedConfidence >= 0 && providedConfidence <= 1) {
  aiConfidence = Number(providedConfidence.toFixed(2));
} else if (providedRequirementId && bestMatch.id !== providedRequirementId && bestMatch.score - selectedMatch.score >= 0.12) {
  aiConfidence = Math.max(0.2, Number((selectedMatch.score - 0.15).toFixed(2)));
}

const confidenceBand = aiConfidence >= 0.8 ? 'high' : aiConfidence >= 0.6 ? 'medium' : 'low';
const summarySignals = selectedMatch.matches.length > 0 ? selectedMatch.matches.slice(0, 5).join(', ') : 'indikasi teks/visual masih minim';

