  json: {
    category_id: categoryId,
    category_name: categoryMeta.name,
    category_weight: categoryMeta.weight,
    source_type: 'ocr_document',
    provided_requirement_id: providedRequirementId || '',
    requirement_id: selectedMatch.id,
    requirement_name: selectedMatch.name,
    requirement_description: selectedMatch.description,
    suggested_requirement_id: bestMatch.id,
    suggested_requirement_name: bestMatch.name,
    ai_confidence: Number(aiConfidence.toFixed(2)),
    confidence_band: confidenceBand,
    ai_summary: `Dokumen paling dekat dengan ${selectedMatch.id} (${selectedMatch.name}). Sinyal utama: ${summarySignals}.`,
    ocr_excerpt: ocrText.slice(0, 500),
    file_name: document.fileName ?? '',
    mime_type: document.mimeType ?? '',
    scoring: {
      best_match: {
        requirement_id: bestMatch.id,
        score: bestMatch.score,
        matches: bestMatch.matches
      },
      selected_match: {
        requirement_id: selectedMatch.id,
        score: Number(aiConfidence.toFixed(2)),
        matches: selectedMatch.matches
      },
      candidates: ranked.map((item) => ({
        requirement_id: item.id,
        score: item.score,
        matches: item.matches
      }))
    }
  },
  binary: {
    document
  }
}];

const source = $node["Scoring Image Evidence"].json ?? {};
const item = $input.first();

const parseJsonString = (value) => {
  const cleaned = String(value)
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  return JSON.parse(cleaned);
};

let raw = item.json?.text ?? item.json?.response ?? item.json?.output ?? item.json;
if (typeof raw === 'string') {
  raw = parseJsonString(raw);
}
if (!raw || typeof raw !== 'object') {
  throw new Error('Basic LLM Chain tidak menghasilkan JSON scoring yang valid.');
}

const aiConfidence = Number(Math.max(0, Math.min(1, Number.parseFloat(String(raw.ai_confidence ?? source.ai_confidence ?? 0))))).toFixed(3);
const requirementId = source.requirement_id;
const categoryId = source.category_id;
const fileName = source.file_name || 'document-uploaded-file';

return [{
  json: {
    ...source,
    ai_confidence: Number(aiConfidence),
    ai_scoring_reason: String(raw.reason ?? '').trim(),
    upload_request: {
      method: 'POST',
      path: `/evidence/categories/${categoryId}/documents`,
      formData: {
        requirement_id: requirementId,
        ai_confidence: aiConfidence
      },
      binary_field: 'document'
    },
    curl_preview: `curl --location -g 'https://experientially-unchallenging-amelie.ngrok-free.dev/api/v1/evidence/categories/${categoryId}/documents' \\\n--header 'Authorization: Bearer REPLACE_WITH_USER_TOKEN' \\\n--form 'requirement_id="${requirementId}"' \\\n--form 'document=@"/${fileName}"' \\\n--form 'ai_confidence="${aiConfidence}"'`
  },
  binary: $node["Scoring Image Evidence"].binary
}];

